export const getChapter = (id: number): Chapter | undefined => 
  chapters.find(ch => ch.id === id);

export const getSection = (chapterId: number, sectionId: string) => {
  const chapter = getChapter(chapterId);
  return chapter?.sections.find(s => s.id === sectionId);
};
